class Solution(object):
    def convertTime(self, current, correct):
        def to_minutes(time_str):
            h, m = map(int, time_str.split(':'))
            return h * 60 + m
        curr_min = to_minutes(current)
        correct_min = to_minutes(correct)
        diff = correct_min - curr_min
        moves = 0
        for increment in [60, 15, 5, 1]:
            moves += diff // increment
            diff %= increment
        return moves
